import { forwardRef } from 'react';

export type IndicatorVariant = 'unsaved' | 'new' | 'unread';
export type IndicatorSize = 'sm' | 'lg';

export interface O9IndicatorProps {
  variant: IndicatorVariant;
  size?: IndicatorSize;
  className?: string;
}

const O9Indicator = forwardRef<HTMLSpanElement, O9IndicatorProps>(
  function O9Indicator({ variant, size = 'lg', className }, ref) {
    const classes = [
      'o9ds-indicator',
      `o9ds-indicator--${variant}`,
      `o9ds-indicator--${size}`,
      className ?? '',
    ]
      .filter(Boolean)
      .join(' ');

    return (
      <span ref={ref} className={classes} aria-hidden="true" />
    );
  }
);

export default O9Indicator;
